python3 - <<'PY'
import requests,re
urls=['https://conexaominasrio.com.br/produto/doce-de-leite-display/','https://www.amazon.com.br/Leite-Port%C3%A3o-Cambu%C3%AD-Display-Tabletes/dp/B0B75QQV7M','https://www.mercadolivre.com.br/doce-de-leite-em-tablete-portao-de-cambui-display-40-un-25g/up/MLBU1426965360']
for url in urls:
 print('\nURL',url)
 html=requests.get(url,headers={'User-Agent':'Mozilla/5.0'},timeout=15).text
 for pat in [r'property="og:image" content="([^"]+)"',r'<meta content="([^"]+)" property="og:image"',r'"image"\s*:\s*"([^"]+)"',r'https?://[^"\']+\.(?:jpg|jpeg|png|webp)[^"\']*']:
  ms=re.findall(pat,html,re.I)
  if ms:
   for m in ms[:10]: print(m.replace('\\/','/'))
   break
PY

